import { useEffect, useState } from "react";
import { Field, Form } from "react-final-form";
import { useNavigate } from "react-router-dom";
import AlertDismissible from "../../../common/AlertDismissible";
import { InputField } from "../../../common/InputText";
import AuthService from "../../services/auth.service";
import UserService from "../../services/user.service";
function ResetPassword(props) {
  const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));
  const navigate = useNavigate();

  const urlParams = new URLSearchParams(window.location.search);
  const token = urlParams.get("token");
  const email = urlParams.get("email");
  const [status, setStatus] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [message, setMessage] = useState();
  const [isFirstLoad, setIsFirstLoad] = useState(false);

  useEffect(async () => {
    const response = await AuthService.reset(token, email);
    setMessage(!!response?.message && response?.message);
    setStatus(!!response.success && response.success);
    setIsLoading(false);
    setIsFirstLoad(true);

    document.body.classList.add("account-page");
    return () => {
      document.body.classList.remove("account-page");
    };
  }, []);

  const validate = async (values) => {
    const errors = {};
    if (!values.password) {
      errors.password = "Required";
    } else if (values.password.length < 6 || values.password.length >= 40) {
      errors.password = "Password length must be between 6 and 40";
    }
    if (!values.confirm) {
      errors.confirm = "Required";
    } else if (values.confirm !== values.password) {
      errors.confirm = "Must match";
    }
    return errors;
  };

  const onSubmit = async (values) => {
    setIsFirstLoad(false);
    setMessage("");
    setIsLoading(true);
    const responseGetUser = await UserService.getUserByEmail(email);
    if (responseGetUser.success) {
      const response = await UserService.updateUserByID({
        userId: responseGetUser?.body?.userId,
        password: values.password,
      });
      // if (!response.success) setMessage(!!response.message && response.message);
      // else setStatus(true);

      setMessage(!!response?.body?.message && response?.body?.message);
      setIsLoading(!!response.success && response.success);
      setStatus(false);

      if (!response.success) return;
      navigate("/login", {
        state: {
          preStatus: "success",
          loginBoldMsg: "You have successfully reset your password!",
          loginMsg: "You can now login with your new credentials",
        },
      });
    }
    setMessage(!!responseGetUser?.message && responseGetUser?.message);
    setIsLoading(false);
    // await sleep(3000);
  };

  const resetForm = (
    <Form
      validate={validate}
      onSubmit={onSubmit}
      render={({
        handleSubmit,
        submitError,
        form,
        submitting,
        pristine,
        values,
      }) => (
        <div className="col-md-12 col-lg-6 login-right">
          <div className="login-header">
            <h3>Reset Your Password</h3>
          </div>
          <form onSubmit={handleSubmit} className="needs-validation" noValidate>
            {!isFirstLoad && (
              <div className="invalid-feedback d-block mb-2">{message}</div>
            )}
            <div
              className={`form-group form-focus mt-4 ${
                values?.password?.length > 0 ? "focused" : ""
              }`}
            >
              <Field
                name="password"
                className="form-control floating"
                label="New Password"
                type="password"
                label_type="focus_label"
                component={InputField}
                disabled={!status}
              />
            </div>
            <div
              className={`form-group form-focus mt-4 ${
                values?.confirm?.length > 0 ? "focused" : ""
              }`}
            >
              <Field
                name="confirm"
                className="form-control floating"
                label="Confirm New Password"
                type="password"
                label_type="focus_label"
                component={InputField}
                disabled={!status}
              />
            </div>
            <button
              className="btn btn-primary btn-block btn-lg login-btn mt-5"
              type="submit"
              disabled={isLoading || !status}
            >
              {!isLoading ? `Reset` : ""}
              {isLoading && (
                <span className="spinner-border spinner-border-sm mb-1"></span>
              )}
            </button>
          </form>
        </div>
      )}
    />
  );

  return (
    <div className="content">
      <div className="container-fluid">
        <div className="row justify-content-center">
          <div className="col-md-8">
            <div className="account-content px-3">
              {isFirstLoad && (
                <AlertDismissible
                  type={status ? "success" : "error"}
                  boldMsg={status ? "Success" : "Error!"}
                  msg={message}
                />
              )}
              {true && (
                <div className="row align-items-center justify-content-center">
                  {resetForm}
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default ResetPassword;
